import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getAlbum } from '../api/albumService';
import { getChansons } from '../api/chansonService';
import { getArtistes } from '../api/artisteService';

export default function AlbumDetail() {
  const { id } = useParams();
  const [album, setAlbum] = useState(null);
  const [chansons, setChansons] = useState([]);
  const [artisteName, setArtisteName] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    Promise.all([getAlbum(id), getChansons(), getArtistes()])
      .then(([albumRes, chansonsRes, artistesRes]) => {
        const albumData = albumRes.data || null;
        setAlbum(albumData);
        setChansons((chansonsRes.data || []).filter((song) => song.albumId === parseInt(id, 10)));

        const artiste = (artistesRes.data || []).find((a) => a.id === albumData?.artisteId);
        setArtisteName(artiste ? artiste.nom : 'Artiste inconnu');
      })
      .catch(() => {
        setAlbum(null);
        setChansons([]);
        setArtisteName('');
      })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="alert alert-secondary">Chargement...</div>;
  if (!album) return <div className="alert alert-danger">Album non trouvé.</div>;

  return (
    <div>
      <div className="row g-4 mb-4">
        <div className="col-md-5">
          <div className="card shadow-sm border-0">
            {album.image ? (
              <img
                src={`/uploads/images/${album.image}`}
                className="card-img-top"
                alt={album.titre}
              />
            ) : (
              <div className="card-img-top bg-secondary text-white py-5 text-center">
                Image non disponible
              </div>
            )}
            <div className="card-body">
              <h1 className="h4">{album.titre}</h1>
              <p className="text-muted mb-2">ID: {album.id}</p>
              <p className="mb-1">Artiste: <strong>{artisteName}</strong></p>
              <p className="mb-3">Album ID: {album.id}</p>
              <div className="d-flex gap-2">
                <Link className="btn btn-outline-primary" to={`/albums/${id}/edit`}>
                  Modifier
                </Link>
                <Link className="btn btn-secondary" to="/albums">
                  Retour à la liste
                </Link>
              </div>
            </div>
          </div>
        </div>

        <div className="col-md-7">
          <div className="card shadow-sm border-0 h-100">
            <div className="card-body">
              <h5 className="card-title">Chansons de l'album</h5>
              {chansons.length === 0 ? (
                <p className="text-muted">Aucune chanson attachée à cet album.</p>
              ) : (
                <ul className="list-group list-group-flush">
                  {chansons.map((chanson) => (
                    <li key={chanson.id} className="list-group-item d-flex justify-content-between align-items-center">
                      <div>
                        <strong>{chanson.titre}</strong>
                        <div className="small text-muted">ID: {chanson.id}</div>
                      </div>
                      <div>
                        {chanson.fichierAudio ? (
                          <a className="btn btn-sm btn-outline-success" href={`/uploads/musics/${chanson.fichierAudio}`} target="_blank" rel="noreferrer">
                            Écouter
                          </a>
                        ) : (
                          <span className="badge bg-secondary">Pas de fichier</span>
                        )}
                      </div>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
